func extractBaseName(resource string) string {
	parts := strings.Fields(resource)
	if len(parts) == 0 {
		return ""
	}
	name := parts[0]
	// Strip path prefix: /usr/bin/ls → ls
	if idx := strings.LastIndexByte(name, '/'); idx >= 0 {
		name = name[idx+1:]
	}
	return strings.ToLower(name)
